const nodes = JSON.parse(JSON.stringify(workflow.nodes || []));
const patchedNodeNames = [];
for (const node of nodes) {
  if (!['Send Final Response', 'Send Final Response1'].includes(String(node.name || ''))) continue;
  const parameters = node.parameters && typeof node.parameters === 'object' ? node.parameters : {};
  const headerParameters = parameters.headerParameters && typeof parameters.headerParameters === 'object'
    ? parameters.headerParameters
    : { parameters: [] };
  const existing = Array.isArray(headerParameters.parameters) ? headerParameters.parameters : [];
  const filtered = existing.filter((entry) => !['content-type', 'access_token'].includes(String(entry?.name || '').toLowerCase()));
  headerParameters.parameters = [
    { name: 'Content-Type', value: 'application/json' },
    { name: 'access_token', value: refreshedAccessToken },
    ...filtered,
  ];
  parameters.headerParameters = headerParameters;
  delete parameters.authentication;
  delete parameters.genericAuthType;
  node.parameters = parameters;
  delete node.credentials;
  patchedNodeNames.push(String(node.name || ''));
